    61→class AuthClientImpl extends AuthClient {
    62→  static final _fc = failureCodeBuilder.category('AAC'); // Auth-AuthClient
    63→  static final _logger = FimberLog('AuthClient');
    64→
    65→  late final APIServerClient _apiClient;
    66→
    67→  QueryRunner get _runner => _apiClient.runner;
    68→
    69→  /// local storage provider
    70→  final ProfileStorage _profileStorage;
    71→
    72→  /// Default constructor
    73→  AuthClientImpl(
    74→    this._profileStorage,
    75→    Locale locale,
    76→    String? appVersion,
    77→  ) {
    78→    _apiClient = APIServerClient(
    79→      locale: locale,
    80→      appVersion: appVersion,
    81→    );
    82→  }
    83→
    84→  @override
    85→
    86→  /// Sign in user to the application with email and password
    87→  Future<Result<Failure, bool>> signInWithPassword(
    88→      String email, String password, bool saveCredentials) async {
    89→    final methodFc = _fc.category('SIP');
    90→
    91→    // Run the query and return result.
    92→    final result = await _runner.runQuery(
    93→      () async {
    94→        if (await AuthUtils.instance.isSignedIn()) {
    95→          await AuthUtils.instance.signOut();
    96→        }
    97→        await Amplify.Auth.signIn(
    98→          username: email,
    99→          password: password,
   100→          options: const SignInOptions(
   101→            pluginOptions: CognitoSignInPluginOptions(
   102→              authFlowType: AuthenticationFlowType.userPasswordAuth,
   103→            ),
   104→          ),
   105→        );
   106→      },
   107→      false,
   108→    );
   109→    if (result.hasLeft) {
   110→      if (result.left is NetworkFailure) {
   111→        return Left(Failure.network(
   112→          code: methodFc.position('001'),
   113→          description: (l10n) =>
   114→              l10n.auth_client__failed_to_authenticate_check_network,
   115→          underlyingException: result.left.underlyingException,
   116→        ));
   117→      }
   118→      if (result.left is InvalidSessionFailure) {
   119→        final e = result.left.underlyingException;
   120→        if (e is AuthException) {
   121→          return Left(await _processAuthException(e, email));
   122→        }
   123→      }
   124→      return Left(result.left);
   125→    }
   126→
   127→    late String userId;
   128→    try {
   129→      userId = await AuthUtils.instance.getUserId();
   130→    } catch (e, stackTrace) {
   131→      _logger.e('failed to get userId', ex: e, stacktrace: stackTrace);
   132→      return Left(Failure.undefined(
   133→        code: methodFc.position('002'),
   134→        underlyingException: e,
   135→        stackTrace: stackTrace,
   136→      ));
   137→    }
   138→
   139→    await _profileStorage.setEmail(email);
   140→    if (saveCredentials) {
   141→      // Cache user password
   142→      await _profileStorage.setPassword(password);
   143→    } else {
   144→      // Remove cached user password
   145→      await _profileStorage.setPassword(null);
   146→    }
   147→
   148→    await _profileStorage.setUserId(userId);
   149→
   150→    // Get team_id and role of the user using direct API call
   151→    // This avoids circular dependency with Repository
   152→    final userInfoResult = await _apiClient.request(
   153→      method: 'GET',
   154→      path: '/users/me',
   155→      responseMapper: UserDetailResponse.fromJson,
   156→    );
   157→    if (userInfoResult.hasLeft) {
   158→      return Left(userInfoResult.left);
   159→    }
   160→
   161→    final user = userInfoResult.right.user;
   162→    final teamId = user.teams
   163→        .where((t) =>
   164→            user.givenUserRoles[t.id!]
   165→                ?.where((r) => !r.deleteFlag)
   166→                .isNotEmpty ??
   167→            false)
   168→        .firstOrNull
   169→        ?.id;
   170→    if (teamId == null) {
   171→      return Left(Failure.undefined(
   172→        code: methodFc.position('003'),
   173→        description: (l10n) => 'User does not belong to any team',
   174→      ));
   175→    }
   176→
   177→    // Cache team_id and role
   178→    await _profileStorage.setTeamId(teamId);
   179→
   180→    return const Right(true);
   181→  }
   182→
   183→  Future<Failure> _processAuthException(AuthException e, String email) async {
   184→    final methodFc = _fc.category('PAEX');
   185→
   186→    final isPasswordIncorrect = e is AuthNotAuthorizedException ||
   187→        (e is UserNotFoundException &&
   188→            e.message == "UserMigration failed with error Incorrect password.");
   189→    final isUserNotFound =
   190→        e is UserNotFoundException && e.message == "User does not exist.";
   191→
   192→    if (isPasswordIncorrect) {
   193→      // パスワードが間違っている場合でも、メール確認状況をチェック
   194→      final emailStatusResult = await _getEmailVerificationStatus(email);
   195→      // もしメール未確認の場合は、そちらのエラーを返す
   196→      if (emailStatusResult is UnconfirmedEmailFailure) {
   197→        return emailStatusResult;
   198→      }
   199→      // それ以外の場合は、パスワード間違いエラーを返す
   200→      return Failure.incorrectPassword(
   201→        code: methodFc.position('001'),
   202→        email: email,
   203→      );
   204→    }
   205→    if (isUserNotFound) {
   206→      return await _getEmailVerificationStatus(email);
   207→    }
   208→
   209→    // アカウント削除後にユーザーが削除予定に入っている場合に signIn しようとすると
   210→    // このエラーになる。この場合は未登録メールアドレスエラーを返す。
   211→    final errorCode = methodFc.position('003');
   212→    if (errorCode == 'EM-AAC-PAEX-003') {
   213→      return Failure.unregisteredEmail(
   214→        code: errorCode,
   215→        email: email,
   216→      );
   217→    }
   218→
   219→    // それ以外の認証エラーは UndefinedFailure として扱う
   220→    return Failure.undefined(
   221→      code: methodFc.position('004'),
   222→      description: (l10n) =>
   223→          l10n.auth_client__failed_to_authenticate_received_error_response,
   224→      underlyingException: e,
   225→    );
   226→  }
   227→
   228→  Future<Failure> _getEmailVerificationStatus(String email) async {
   229→    final methodFc = _fc.category('GVS');
   230→
   231→    // Run the query and return result.
   232→    final result = await _apiClient.request(
   233→      method: 'GET',
   234→      path:
   235→          '/auth/users/verification-status?email=${Uri.encodeQueryComponent(email)}',
   236→      responseMapper: EmailVerificationStatusResponse.fromJson,
   237→      authenticated: false,
   238→    );
   239→    if (result.hasLeft) {
   240→      return result.left;
   241→    }
   242→
   243→    final status = result.right.status;
   244→    switch (status) {
   245→      case EmailVerificationStatus.notVerified:
   246→        // これが返ってくるケースではサインアップフローの途中で離脱したユーザーがログインしようとした場合
   247→        // この時は ConfirmCodePage へ遷移するため、email, isInSignUpFlow == true を設定する
   248→        // コード検証の途中で別のユーザーにログインしたり、別のユーザーを削除したりするとこれらが不整合な状態になるため
   249→        await _profileStorage.setEmail(email);
   250→        await _profileStorage.setIsInSignUpFlow(true);
   251→        return Failure.unconfirmedEmail(
   252→          code: methodFc.position('001'),
   253→          email: email,
   254→        );
   255→      case EmailVerificationStatus.notCreated:
   256→        return Failure.unregisteredEmail(
   257→          code: methodFc.position('002'),
   258→          email: email,
   259→        );
   260→      default:
   261→        return Failure.undefined(
   262→          code: methodFc.position('003'),
   263→          description: (l10n) => l10n.auth_client__unknown_verification_status,
   264→        );
   265→    }
   266→  }
   267→
   268→  @override
   269→
   270→  /// Sign out user from application
   271→  Future<Result<Failure, bool>> signOut() async {
   272→    // TODO: After disconnecting network,
   273→    // goTrueClient.signOut() throws a network exception at the first call,
   274→    // but this method return null without any exceptions at the second call.
   275→
   276→    // Run the query and return result.
   277→    final result = await _runner.runQuery(
   278→      () => AuthUtils.instance.signOut(),
   279→    );
   280→    // Delete cache regardless of the result
   281→    await Future.wait([
   282→      _profileStorage.setUserId(null),
   283→      _profileStorage.setTeamId(null),
   284→    ]);
   285→    if (result.hasLeft) {
   286→      return Left(result.left);
   287→    } else {
   288→      return const Right(true);
   289→    }
   290→  }
   291→
   292→  @override
   293→  Future<Result<Failure, bool>> changePassword(
   294→      {required String newPassword, required bool saveCredentials}) async {
   295→    // Run the query and return result.
   296→    final result = await _apiClient.request(
   297→      method: 'PUT',
   298→      path: '/users/me/password',
   299→      data: PasswordChangeRequest(
   300→        password: newPassword,
   301→        passwordConfirmation: newPassword,
   302→      ).toJson(),
   303→    );
   304→    if (result.hasLeft) {
   305→      return Left(result.left);
   306→    }
   307→
   308→    if (saveCredentials) {
   309→      // Save if we need to save credentials
   310→      await _profileStorage.setPassword(newPassword);
   311→    } else {
   312→      // Remove cached user password
   313→      await _profileStorage.setPassword(null);
   314→    }
   315→    return const Right(true);
   316→  }
   317→
   318→  @override
   319→  Future<Result<Failure, bool>> forgotPassword({required String email}) async {
   320→    // Run the query and return result.
   321→    final result = await _apiClient.request(
   322→      method: 'POST',
   323→      path: '/auth/password-reset/email',
   324→      data: PasswordResetRequest(
   325→        email: email,
   326→      ).toJson(),
   327→      authenticated: false,
   328→    );
   329→    if (result.hasLeft) {
   330→      return Left(result.left);
   331→    }
   332→    return const Right(true);
   333→  }
   334→
   335→  @override
   336→  Future<Result<Failure, String>> signUp({
   337→    required String email,
   338→    required String password,
   339→    required DateTime birthday,
   340→  }) async {
   341→    // Run the query and return result.
   342→    final result = await _apiClient.request(
   343→      method: 'POST',
   344→      path: '/auth/signup',
   345→      data: SignUpRequest(
   346→        name: email,
   347→        email: email,
   348→        password: password,
   349→        birthday: birthday,
   350→      ).toJson(),
   351→      responseMapper: SignUpResponse.fromJson,
   352→      authenticated: false,
   353→    );
   354→    if (result.hasLeft) {
   355→      return Left(result.left);
   356→    }
   357→
   358→    final userId = result.right.userId;
   359→    await Future.wait([
   360→      _profileStorage.setIsInSignUpFlow(true),
   361→      _profileStorage.setEmail(email),
   362→      _profileStorage.setPendingSignUpUserId(userId),
   363→      _profileStorage.setUserId(userId),
   364→      _profileStorage.setPassword(password),
   365→      _profileStorage.setBirthday(birthday),
   366→    ]);
   367→    return Right(userId);
   368→  }
   369→
   370→  @override
   371→  Future<Result<Failure, String>> verifyCode({
   372→    required String code,
   373→  }) async {
   374→    assert(_profileStorage.getIsInSignUpFlow() ?? false);
   375→
   376→    final email = await _profileStorage.getEmail();
   377→    assert(email != null);
   378→
   379→    // Run the query and return result.
   380→    final result = await _apiClient.request(
   381→      method: 'GET',
   382→      path: '/auth/code-verification',
   383→      queryParameters: VerifyCodeRequest(
   384→        email: email!,
   385→        code: code,
   386→      ).toJson(),
   387→      responseMapper: VerifyCodeResponse.fromJson,
   388→      authenticated: false,
   389→    );
   390→    if (result.hasLeft) {
   391→      return Left(result.left);
   392→    }
   393→    return Right(result.right.token);
   394→  }
   395→
   396→  @override
   397→  Future<Result<Failure, void>> completeSignUp({required String token}) async {
   398→    assert(_profileStorage.getIsInSignUpFlow() ?? false);
   399→
   400→    final pendingUserId = _profileStorage.getPendingSignUpUserId();
   401→    final userId = pendingUserId ?? _profileStorage.getUserId();
   402→    final password = await _profileStorage.getPassword();
   403→
   404→    assert(userId != null);
   405→    assert(password != null);
   406→
   407→    // Run the query and return result.
   408→    final result = await _apiClient.request(
   409→      method: 'PUT',
   410→      path: '/auth/password-reset/initial',
   411→      data: SetUserInitialPasswordRequest(
   412→        userId: userId!,
   413→        password: password!,
   414→        token: token,
   415→      ).toJson(),
   416→      authenticated: false,
   417→    );
   418→    await Future.wait([
   419→      _profileStorage.setIsInSignUpFlow(false),
   420→      _profileStorage.setPendingSignUpUserId(null),
   421→    ]);
   422→    if (result.hasLeft) {
   423→      return Left(result.left);
   424→    }
   425→    return Right(null);
   426→  }
   427→
   428→  @override
   429→  Future<Result<Failure, bool>> deleteAccount() async {
   430→    // Run the query and return result.
   431→    final result = await _apiClient.request(
   432→      method: 'DELETE',
   433→      path: '/users/me',
   434→    );
   435→    if (result.hasLeft) {
   436→      return Left(result.left);
   437→    }
   438→
   439→    // Sign out and clear all cached data after successful account deletion
   440→    await Future.wait([
   441→      AuthUtils.instance.signOut(),
   442→      _profileStorage.setUserId(null),
   443→      _profileStorage.setTeamId(null),
   444→      _profileStorage.setEmail(null),
   445→      _profileStorage.setPassword(null),
   446→      _profileStorage.setIsInSignUpFlow(false),
   447→    ]);
   448→
   449→    return const Right(true);
   450→  }
   451→
   452→  @override
   453→  Future<bool> get isLoggedIn async {
   454→    return await AuthUtils.instance.isSignedIn();
   455→  }
   456→}
