import 'package:freezed_annotation/freezed_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/constants.dart';

part 'profile.freezed.dart';
part 'profile.g.dart';

@freezed
abstract class Profile with _$Profile {
  const Profile._();

  @JsonSerializable(
      explicitToJson: true, fieldRename: Constants.modelFieldRename)
  const factory Profile({
    required String id,
    String? username,
    String? imageUrl,
    String? presignedImageUrl,
    DateTime? createdAt, // assumes UTC
    DateTime? updatedAt, // assumes UTC
  }) = _Profile;

  factory Profile.fromJson(Map<String, dynamic> json) =>
      _$ProfileFromJson(json);
}

