///
/// 複数メールでのサインアップ/ログイン時に各メールの情報を保持するモデル
@freezed
abstract class SignUpContext with _$SignUpContext {
  const SignUpContext._();

  @JsonSerializable(
      explicitToJson: true, fieldRename: Constants.modelFieldRename)
  const factory SignUpContext({
    required String email,
    required String password,
    required DateTime birthday,
    required SignUpFlowType flowType,
    required DateTime lastUpdated,
  }) = _SignUpContext;

  factory SignUpContext.fromJson(Map<String, dynamic> json) =>
      _$SignUpContextFromJson(json);
}

