  ///////////////////////////////////////////////////////////////////////////
  // SignUpContext methods
  ///////////////////////////////////////////////////////////////////////////

  @override
  Future<bool> setSignUpContext(String email, SignUpContext context) async {
    final allContexts = await getAllSignUpContexts();
    allContexts[email] = context;

    // 最新 3 件のみ保持（古いものを削除）
    if (allContexts.length > 3) {
      final sortedEntries = allContexts.entries.toList()
        ..sort((a, b) => b.value.lastUpdated.compareTo(a.value.lastUpdated));
      allContexts
        ..clear()
        ..addAll(Map.fromEntries(sortedEntries.take(3)));
    }

    final jsonMap = allContexts
        .map((key, value) => MapEntry(key, jsonEncode(value.toJson())));
    await _updateStringValueOnSecureStorage(
      ProfileStorage.prefsKeySignUpContexts,
      jsonEncode(jsonMap),
    );
    return true;
  }

  @override
  Future<bool> removeSignUpContext(String email) async {
    final allContexts = await getAllSignUpContexts();
    allContexts.remove(email);

    if (allContexts.isEmpty) {
      await _updateStringValueOnSecureStorage(
        ProfileStorage.prefsKeySignUpContexts,
        null,
      );
    } else {
      final jsonMap = allContexts
          .map((key, value) => MapEntry(key, jsonEncode(value.toJson())));
      await _updateStringValueOnSecureStorage(
        ProfileStorage.prefsKeySignUpContexts,
        jsonEncode(jsonMap),
      );
    }
    return true;
  }

  @override
  Future<bool> setActiveEmail(String? email) async {
    await _updateStringValueOnSecureStorage(
      ProfileStorage.prefsKeyActiveEmail,
      email,
    );
    return true;
  }

