  Future<bool> clearAllSignUpContexts() async {
    await _updateStringValueOnSecureStorage(
      ProfileStorage.prefsKeySignUpContexts,
      null,
    );
    await _updateStringValueOnSecureStorage(
      ProfileStorage.prefsKeyActiveEmail,
      null,
    );
    return true;
  }

  @override
  Future<SignUpContext?> getSignUpContext(String email) async {
    final allContexts = await getAllSignUpContexts();
    return allContexts[email];
  }

  @override
  Future<Map<String, SignUpContext>> getAllSignUpContexts() async {
    final jsonString = await _readStringValueOnSecureStorage(
      ProfileStorage.prefsKeySignUpContexts,
    );
    if (jsonString == null) return {};

    try {
      final Map<String, dynamic> jsonMap = jsonDecode(jsonString);
      return jsonMap.map((key, value) {
