  @override
  Future<Result<Failure, bool>> forgotPassword({required String email}) async {
    // Run the query and return result.
    final result = await _apiClient.request(
      method: 'POST',
      path: '/auth/password-reset/email',
      data: PasswordResetRequest(
        email: email,
      ).toJson(),
      authenticated: false,
    );
